52	  async findFacts(filter: FactFilter): Promise<Fact[]> {
53	    return this.factStore.query(filter);
54	  }
55	
56	  /**
57	   * 查询 Knowledge。
58	   *
59	   * 执行顺序：
60	   *   1. 按时间/身份条件（entityId, factId, source, atChapter）从 Store 取候选记录
61	   *   2. 非 history 模式下，对每个 (entityId, factId) 取 knownSince DESC + rowid DESC 最新记录
62	   *   3. 最后统一应用可见性过滤（includeSealed / minConfidence / factPredicate）
63	   *
64	   * 关键：minConfidence 绝不能在步骤 1 预过滤，否则较新的封印记录（confidence=0）
65	   * 会被误排除，导致旧的正确记录被当成当前认知返回。
