79	      // includeSealed 过滤：默认隐藏 confidence <= 0 的封印记录
80	      if (!filter.includeSealed && knowledge.confidence <= 0) return false;
81	      // minConfidence 只作用于非封印记录；封印记录的可见性由 includeSealed 独立控制
82	      if (filter.minConfidence !== undefined && knowledge.confidence > 0 && knowledge.confidence < filter.minConfidence) return false;
83	      if (filter.factSubject || filter.factPredicate) {
84	        const fact = this.factStore.getById(knowledge.factId);
85	        if (!fact) return false;
86	        if (filter.factSubject && fact.subject !== filter.factSubject) return false;
87	        if (filter.factPredicate && fact.predicate !== filter.factPredicate) return false;
88	      }
