102	      events = this.eventStore.getByDependentFactIds(filter.dependentFactIds, kind);
103	    } else if (filter.subject) {
104	      events = this.eventStore.getBySubject(filter.subject, filter.fromChapter, kind);
105	    } else if (filter.type) {
106	      events = this.eventStore.getByType(filter.type, filter.fromChapter, kind);
107	    } else {
108	      events = this.eventStore.getByChapterRange(filter.fromChapter ?? 0, filter.toChapter, kind);
109	    }
