112	      if (filter.type && event.type !== filter.type) return false;
113	      if (filter.subject && event.params['subject'] !== filter.subject) return false;
114	      if (filter.fromChapter !== undefined && event.chapter < filter.fromChapter) return false;
115	      if (filter.toChapter !== undefined && event.chapter > filter.toChapter) return false;
116	      if (kind !== 'all' && event.kind !== kind) return false;
117	      return true;
118	    });
119	  }
