121	  /** 查询实体注册表。实体状态仍应通过 Fact 查询获得。 */
122	  async findEntities(filter: EntityFilter): Promise<EntityRecord[]> {
123	    if (!this.db) {
124	      throw new Error('ENTITY_QUERY_UNSUPPORTED: 当前 QueryEngine 未提供 SQLite 数据库连接');
125	    }
126	
127	    const conditions: string[] = [];
128	    const params: unknown[] = [];
129	
130	    if (filter.id) {
131	      conditions.push('id = ?');
132	      params.push(filter.id);
133	    }
134	    if (filter.name) {
135	      conditions.push('name = ?');
136	      params.push(filter.name);
137	    }
138	    if (filter.nameContains) {
139	      conditions.push('name LIKE ?');
140	      params.push(`%${filter.nameContains}%`);
141	    }
142	    if (filter.kind) {
143	      const kinds = Array.isArray(filter.kind) ? filter.kind : [filter.kind];
144	      conditions.push(`kind IN (${kinds.map(() => '?').join(',')})`);
145	      params.push(...kinds);
146	    }
147	    if (filter.appearedBefore !== undefined) {
148	      conditions.push('first_appearance <= ?');
149	      params.push(filter.appearedBefore);
150	    }
151	    if (filter.appearedAfter !== undefined) {
152	      conditions.push('first_appearance >= ?');
153	      params.push(filter.appearedAfter);
154	    }
155	
156	    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
157	    const rows = this.db.prepare(
158	      `SELECT id, name, kind, description, first_appearance, registered_at_event
159	       FROM entities ${whereClause}
160	       ORDER BY first_appearance ASC, id ASC`
161	    ).all(...params) as EntityRow[];
162	
163	    return rows.map(row => ({
164	      id: row.id,
165	      name: row.name,
166	      kind: row.kind,
167	      description: row.description ?? undefined,
168	      registeredAtChapter: row.first_appearance,
