6	import { describe, expect, it, beforeEach } from 'vitest';
7	import { CoreNarrativeQueryEngine } from '../../src/core/query-engine.js';
8	import { SQLiteFactStoreAdapter } from '../../src/adapters/sqlite/fact-store.js';
9	import { SQLiteKnowledgeStoreAdapter } from '../../src/adapters/sqlite/knowledge-store.js';
