13	  let factStore: SQLiteFactStoreAdapter;
14	  let knowledgeStore: SQLiteKnowledgeStoreAdapter;
15	  let eventStore: SQLiteEventStoreAdapter;
16	  let queryEngine: CoreNarrativeQueryEngine;
17	
18	  beforeEach(() => {
19	    factStore = new SQLiteFactStoreAdapter(':memory:', 'query_test');
20	    const db = factStore.getDatabase();
21	
22	    db.exec(`
23	      INSERT OR IGNORE INTO entities (id, name, kind, first_appearance, registered_at_event)
24	      VALUES
25	        ('ent_zhangsan', '张三', 'entity', 1, 'evt_origin_01'),
26	        ('ent_lisi', '李四', 'entity', 1, 'evt_origin_01'),
27	        ('ent_gumu', '古墓', 'place', 1, 'evt_origin_01');
28	
29	      INSERT OR IGNORE INTO events (id, kind, type, chapter, description, params_json, context, fact_group_id)
30	      VALUES
31	        ('evt_origin_01', 'business', 'origin', 1, '初始设定', '{"subject":"ent_zhangsan"}', 'global', 'evt_origin_01'),
32	        ('evt_system_01', 'system', 'schema', 2, '系统事件', '{}', 'global', 'evt_system_01'),
33	        ('evt_discover_20', 'business', 'discover', 20, '发现秘密', '{"subject":"ent_zhangsan"}', 'global', 'evt_discover_20');
34	    `);
35	
36	    knowledgeStore = new SQLiteKnowledgeStoreAdapter(db);
37	    eventStore = new SQLiteEventStoreAdapter(db);
38	    queryEngine = new CoreNarrativeQueryEngine(factStore, knowledgeStore, eventStore);
39	  });
40	
41	  it('findFacts 默认遵守当前态查询语义', async () => {
42	    const oldFact = factStore.assert({
43	      subject: 'ent_zhangsan',
44	      predicate: 'realm',
45	      value: '筑基期',
46	      certainty: 'canonical',
47	      causeEvent: 'evt_origin_01',
48	      validFrom: 1,
49	      validTo: null,
50	      embeddingText: '',
51	    });
52	    factStore.update(oldFact.id, '金丹期', 'evt_discover_20', 20);
53	
54	    const current = await queryEngine.findFacts({
55	      subject: 'ent_zhangsan',
56	      predicate: 'realm',
57	      atChapter: 30,
58	    });
59	    expect(current.map(f => f.value)).toEqual(['金丹期']);
60	
61	    const history = await queryEngine.findFacts({
62	      subject: 'ent_zhangsan',
63	      predicate: 'realm',
64	      atChapter: 30,
65	      mode: 'history',
66	    });
67	    expect(history.map(f => f.value)).toContain('筑基期');
68	    expect(history.map(f => f.value)).toContain('金丹期');
69	  });
70	
71	  it('findKnowledge 默认返回最新有效认知并隐藏 sealed 记录', async () => {
72	    const fact = factStore.assert({
73	      subject: 'ent_gumu',
74	      predicate: 'secret',
75	      value: '藏有传送阵',
76	      certainty: 'canonical',
77	      causeEvent: 'evt_discover_20',
78	      validFrom: 20,
79	      validTo: null,
80	      embeddingText: '',
81	    });
82	
83	    knowledgeStore.create({
84	      factId: fact.id,
85	      entityId: 'ent_zhangsan',
86	      knownSince: 20,
87	      source: 'self_action',
88	      confidence: 1,
89	    });
90	    knowledgeStore.create({
91	      factId: fact.id,
92	      entityId: 'ent_zhangsan',
93	      knownSince: 30,
94	      source: 'memory_seal',
95	      confidence: 0,
96	      previousConfidence: 1,
97	      updatedAtEvent: 'evt_discover_20',
98	    });
99	
100	    const visible = await queryEngine.findKnowledge({
101	      entityId: 'ent_zhangsan',
102	      factPredicate: 'secret',
103	      atChapter: 40,
104	    });
105	    expect(visible).toEqual([]);
106	
107	    const sealed = await queryEngine.findKnowledge({
108	      entityId: 'ent_zhangsan',
109	      factPredicate: 'secret',
110	      atChapter: 40,
111	      includeSealed: true,
112	    });
113	    expect(sealed).toHaveLength(1);
114	    expect(sealed[0]!.source).toBe('memory_seal');
115	  });
116	
117	  it('findEvents 默认只返回 business 事件', async () => {
118	    const business = await queryEngine.findEvents({ fromChapter: 1, toChapter: 10 });
119	    expect(business.map(event => event.id)).toContain('evt_origin_01');
120	    expect(business.map(event => event.id)).not.toContain('evt_system_01');
121	
122	    const all = await queryEngine.findEvents({ fromChapter: 1, toChapter: 10, kind: 'all' });
123	    expect(all.map(event => event.id)).toContain('evt_system_01');
124	  });
125	
126	  it('findEntities 支持 id/name/kind 的轻量查询', async () => {
127	    const byKind = await queryEngine.findEntities({ kind: 'place' });
128	    expect(byKind.map(entity => entity.id)).toEqual(['ent_gumu']);
129	
130	    const byName = await queryEngine.findEntities({ nameContains: '张' });
131	    expect(byName.map(entity => entity.id)).toEqual(['ent_zhangsan']);
